div.style:
display:none; position:fixed; inset:0; z-index:1040;
background:rgba(0,0,0,0.35); backdrop-filter:blur(2px);
transition:opacity 0.25s;

display:none; position:fixed;
top:50%; left:50%;
transform:translate(-50%, -50%) scale(0.92);
z-index:1050;
background:#ffffff;
border-radius:20px;
box-shadow:0 20px 60px rgba(0,0,0,0.18);
width:90%; max-width:440px;
opacity:0;
transition:transform 0.3s cubic-bezier(.34,1.56,.64,1), opacity 0.25s;

div.script:
function showBookingConfirm() {
    var form = document.getElementById('spaceBookingForm');
    if (!form.checkValidity()) {
        form.reportValidity();
        return;
    }

    // Fill popup details
    var date      = document.getElementById('bookDate').value;
    var startVal  = parseFloat(document.getElementById('bookStart').value);
    var endVal    = parseFloat(document.getElementById('bookEnd').value);

    function toTime(v) {
        var h = Math.floor(v);
        var m = Math.round((v - h) * 60);
        return (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;
}

    // Space name from page heading (h2)
    var heading = document.querySelector('.lib-page-header h2');
    var spaceName = heading ? heading.textContent.replace('— Booking Calendar','').trim() : '—';

    document.getElementById('popupSpaceName').textContent = spaceName;
    document.getElementById('popupDate').textContent      = date || '—';
    document.getElementById('popupTime').textContent      = (date ? toTime(startVal) + ' – ' + toTime(endVal) : '—');

    // Show overlay + popup
    var overlay = document.getElementById('bookingOverlay');
    var popup   = document.getElementById('bookingPopup');
    overlay.style.display = 'block';
    popup.style.display   = 'block';
   setTimeout(function() {
        overlay.style.opacity  = '1';
        popup.style.opacity    = '1';
        popup.style.transform  = 'translate(-50%, -50%) scale(1)';
    }, 10);
}

function closeBookingPopup() {
    var overlay = document.getElementById('bookingOverlay');
    var popup   = document.getElementById('bookingPopup');
    popup.style.transform  = 'translateY(100%)';
    overlay.style.opacity  = '0';
    setTimeout(function() {
        popup.style.display   = 'none';
        overlay.style.display = 'none';
    }, 350);
}

function submitBooking() {
    document.getElementById('spaceBookingForm').submit();
}

